window.REPERTONE_LOGO_DATA = 'data:image/jpeg;base64,';
(function(){
  var logo = window.REPERTONE_LOGO_DATA;
  document.documentElement.style.setProperty('--logo-image', 'url("' + logo + '")');
  document.addEventListener('DOMContentLoaded', function(){
    document.querySelectorAll('[data-logo]').forEach(function(img){ img.src = logo; });
  });
})();
